 12→/// - ToByteArray:
 13→///     1. ToByteArray -> [u8;32]
 14→///     2. ToByteArrays -> [[u8;32]; NUM_FIELDS]
 15→///     3. const NumFields -> usize (can be used to get ToByteArrays)
 16→/// - DataHasher Hash -> [u8;32]
 17→///
 18→/// - Attribute Macros:
 19→///     1. hash
 20→///        hash to bn254 field size (less than 254 bit), hash with keccak256 and truncate to 31 bytes
 21→///     2. skip
 22→///        ignore field
 23→///     3. flatten
 24→///        flatten nested struct or vector
 25→///
 26→/// Derive macro for ToByteArray
 27→/// - Struct:
 28→///   - every field must implement ToByteArray
 29→///   - impl ToByteArray for Struct -> returns hash of all fields
 30→///   - impl DataHasher for Struct -> returns hash of all fields
 31→/// - Options (primitive types PT):
 32→///     - Option<PT> -> [u8;32] -> Some: [32 - type_bytes_len..] 32 - index type_bytes_len -1 = [1] (BE prefix) , None: [0;32]
 33→/// - Option (General):
 34→///     - Option<T> T must implement Hash -> Some: Hash(T::hash), None: [0u8;32]
 35→/// - Nested Structs:
 36→///     - to_byte_array -> hash of all fields
 37→/// - Arrays (u8):
 38→///     1. LEN < 32 implementation of ToByteArray is provided
 39→///     2. LEN >= 32  needs to be handled (can be truncated or implement custom ToByteArray)
 40→/// - Arrays:
 41→///     1. if elements implement ToByteArray and are less than 13, hash of all elements
 42→///     2. More elements than 13 -> manual implementation or hash to field size
 43→/// - Vec<T>:
 44→///     - we do not provide a blanket implementation since it could fail in production once a vector fills up
 45→///     - users need to hash to field size or do a manual implementation
 46→/// - Strings:
 47→///     - we do not provide a blanket implementation since it could fail in production once a string fills up
 48→///     - users need to hash to field size or do a manual implementation
 49→/// - Enums, References, SmartPointers:
 50→///     - Not supported
 51→pub(crate) fn derive_light_hasher(input: ItemStruct) -> Result<TokenStream> {
 52→    derive_light_hasher_with_hasher(input, &quote!(::light_hasher::Poseidon))
 53→}
