 55→pub(crate) fn derive_light_hasher_sha(input: ItemStruct) -> Result<TokenStream> {
 56→    // Use SHA256-specific validation (no field count limits)
 57→    validate_input_sha(&input)?;
 58→
 59→    let generics = input.generics.clone();
 60→
 61→    let fields = match &input.fields {
 62→        Fields::Named(fields) => fields.clone(),
 63→        _ => unreachable!("Validation should have caught this"),
 64→    };
 65→
 66→    let field_count = fields.named.len();
 67→
 68→    let to_byte_array_impl = generate_to_byte_array_impl_sha(&input.ident, &generics, field_count)?;
 69→    let data_hasher_impl = generate_data_hasher_impl_sha(&input.ident, &generics)?;
 70→
 71→    Ok(quote! {
 72→        #to_byte_array_impl
 73→
 74→        #data_hasher_impl
 75→    })
 76→}
 77→
 78→fn derive_light_hasher_with_hasher(input: ItemStruct, hasher: &TokenStream) -> Result<TokenStream> {
 79→    // Validate the input structure
 80→    validate_input(&input)?;
 81→
 82→    let generics = input.generics.clone();
 83→
 84→    // After validation, we know this is a named field struct
 85→    let fields = match &input.fields {
 86→        Fields::Named(fields) => fields.clone(),
 87→        _ => unreachable!("Validation should have caught this"),
 88→    };
 89→
 90→    let field_count = fields.named.len();
 91→    let flatten_field_exists = fields
 92→        .named
 93→        .iter()
 94→        .any(|field| get_field_attribute(field) == FieldAttribute::Flatten);
 95→
 96→    // Create processing context
 97→    let mut context = FieldProcessingContext::new(flatten_field_exists);
 98→
 99→    // Process each field
100→    fields.named.iter().enumerate().for_each(|(i, field)| {
101→        process_field(field, i, &mut context);
102→    });
103→
104→    let to_byte_array_impl = generate_to_byte_array_impl_with_hasher(
105→        &input.ident,
106→        &generics,
107→        field_count,
108→        &context,
109→        hasher,
110→    )?;
111→
112→    let data_hasher_impl = generate_data_hasher_impl(&input.ident, &generics, &context)?;
113→
114→    // Combine implementations
115→    Ok(quote! {
116→        #to_byte_array_impl
117→
118→        #data_hasher_impl
119→    })
120→}
