 45→/// [Concurrent Merkle tree](https://drive.google.REDACTED)
 46→/// which allows for multiple requests of updating leaves, without making any
 47→/// of the requests invalid, as long as they are not modyfing the same leaf.
 48→///
 49→/// When any of the above happens, some of the concurrent requests are going to
 50→/// be invalid, forcing the clients to re-generate the Merkle proof. But that's
 51→/// still better than having such a failure after any update happening in the
 52→/// middle of requesting the update.
 53→///
 54→/// Due to ability to make a decent number of concurrent update requests to be
 55→/// valid, no lock is necessary.
 56→#[repr(C)]
 57→#[derive(Debug)]
 58→// TODO(vadorovsky): The only reason why are we still keeping `HEIGHT` as a
 59→// const generic here is that removing it would require keeping a `BoundecVec`
 60→// inside `CyclicBoundedVec`. Casting byte slices to such nested vector is not
 61→// a trivial task, but we might eventually do it at some point.
 62→pub struct ConcurrentMerkleTree<H, const HEIGHT: usize>
 63→where
 64→    H: Hasher,
 65→{
 66→    pub height: usize,
 67→    pub canopy_depth: usize,
 68→
 69→    next_index: *mut usize,
 70→    sequence_number: *mut usize,
 71→    rightmost_leaf: *mut [u8; 32],
 72→
 73→    /// Hashes of subtrees.
 74→    pub filled_subtrees: BoundedVec<[u8; 32]>,
 75→    /// History of Merkle proofs.
 76→    pub changelog: CyclicBoundedVec<ChangelogEntry<HEIGHT>>,
 77→    /// History of roots.
 78→    pub roots: CyclicBoundedVec<[u8; 32]>,
 79→    /// Cached upper nodes.
 80→    pub canopy: BoundedVec<[u8; 32]>,
 81→
 82→    pub _hasher: PhantomData<H>,
 83→}
 84→
 85→pub type ConcurrentMerkleTree26<H> = ConcurrentMerkleTree<H, 26>;
 86→
 87→impl<H, const HEIGHT: usize> ConcurrentMerkleTree<H, HEIGHT>
 88→where
 89→    H: Hasher,
 90→{
 91→    /// Number of nodes to include in canopy, based on `canopy_depth`.
 92→    #[inline(always)]
 93→    pub fn canopy_size(canopy_depth: usize) -> usize {
 94→        (1 << (canopy_depth + 1)) - 2
 95→    }
 96→
 97→    /// Size of the struct **without** dynamically sized fields (`BoundedVec`,
 98→    /// `CyclicBoundedVec`).
 99→    pub fn non_dyn_fields_size() -> usize {
100→        // height
101→        mem::size_of::<usize>()
102→        // changelog_capacity
103→        + mem::size_of::<usize>()
104→        // next_index
105→        + mem::size_of::<usize>()
106→        // sequence_number
107→        + mem::size_of::<usize>()
108→        // rightmost_leaf
109→        + mem::size_of::<[u8; 32]>()
110→        // filled_subtrees (metadata)
111→        + mem::size_of::<BoundedVecMetadata>()
112→        // changelog (metadata)
113→        + mem::size_of::<CyclicBoundedVecMetadata>()
114→        // roots (metadata)
115→        + mem::size_of::<CyclicBoundedVecMetadata>()
116→        // canopy (metadata)
117→        + mem::size_of::<BoundedVecMetadata>()
118→    }
119→
120→    // TODO(vadorovsky): Make a macro for that.
121→    pub fn size_in_account(
122→        height: usize,
123→        changelog_size: usize,
124→        roots_size: usize,
125→        canopy_depth: usize,
126→    ) -> usize {
127→        // non-dynamic fields
128→        Self::non_dyn_fields_size()
129→        // filled_subtrees
130→        + mem::size_of::<[u8; 32]>() * height
131→        // changelog
132→        + mem::size_of::<ChangelogEntry<HEIGHT>>() * changelog_size
133→        // roots
134→        + mem::size_of::<[u8; 32]>() * roots_size
135→        // canopy
136→        + mem::size_of::<[u8; 32]>() * Self::canopy_size(canopy_depth)
137→    }
138→
139→    fn check_size_constraints_new(
140→        height: usize,
141→        changelog_size: usize,
142→        roots_size: usize,
143→        canopy_depth: usize,
144→    ) -> Result<(), ConcurrentMerkleTreeError> {
145→        if height == 0 || HEIGHT == 0 {
146→            return Err(ConcurrentMerkleTreeError::HeightZero);
147→        }
148→        if height != HEIGHT {
149→            return Err(ConcurrentMerkleTreeError::InvalidHeight(HEIGHT));
150→        }
151→        if canopy_depth > height {
152→            return Err(ConcurrentMerkleTreeError::CanopyGeThanHeight);
153→        }
154→        // Changelog needs to be at least 1, because it's used for storing
155→        // Merkle paths in `append`/`append_batch`.
156→        if changelog_size == 0 {
157→            return Err(ConcurrentMerkleTreeError::ChangelogZero);
158→        }
159→        if roots_size == 0 {
160→            return Err(ConcurrentMerkleTreeError::RootsZero);
161→        }
162→        Ok(())
163→    }
164→
165→    fn check_size_constraints(&self) -> Result<(), ConcurrentMerkleTreeError> {
166→        Self::check_size_constraints_new(
167→            self.height,
168→            self.changelog.capacity(),
169→            self.roots.capacity(),
170→            self.canopy_depth,
171→        )
172→    }
173→
174→    pub fn new(
175→        height: usize,
176→        changelog_size: usize,
177→        roots_size: usize,
178→        canopy_depth: usize,
179→    ) -> Result<Self, ConcurrentMerkleTreeError> {
180→        Self::check_size_constraints_new(height, changelog_size, roots_size, canopy_depth)?;
181→
182→        let layout = Layout::new::<usize>();
183→        let next_index = unsafe { alloc::alloc(layout) as *mut usize };
184→        if next_index.is_null() {
185→            handle_alloc_error(layout);
186→        }
187→        unsafe { *next_index = 0 };
188→
189→        let layout = Layout::new::<usize>();
190→        let sequence_number = unsafe { alloc::alloc(layout) as *mut usize };
191→        if sequence_number.is_null() {
192→            handle_alloc_error(layout);
193→        }
194→        unsafe { *sequence_number = 0 };
195→
196→        let layout = Layout::new::<[u8; 32]>();
197→        let rightmost_leaf = unsafe { alloc::alloc(layout) as *mut [u8; 32] };
198→        if rightmost_leaf.is_null() {
199→            handle_alloc_error(layout);
200→        }
201→        unsafe { *rightmost_leaf = [0u8; 32] };
202→
203→        Ok(Self {
204→            height,
205→            canopy_depth,
206→
207→            next_index,
208→            sequence_number,
209→            rightmost_leaf,
210→
211→            filled_subtrees: BoundedVec::with_capacity(height),
212→            changelog: CyclicBoundedVec::with_capacity(changelog_size),
213→            roots: CyclicBoundedVec::with_capacity(roots_size),
214→            canopy: BoundedVec::with_capacity(Self::canopy_size(canopy_depth)),
215→
216→            _hasher: PhantomData,
217→        })
218→    }
219→
220→    /// Initializes the Merkle tree.
221→    pub fn init(&mut self) -> Result<(), ConcurrentMerkleTreeError> {
222→        self.check_size_constraints()?;
223→
224→        // Initialize root.
225→        let root = H::zero_bytes()[self.height];
226→        self.roots.push(root);
227→
228→        // Initialize changelog.
229→        let path = ChangelogPath::from_fn(|i| Some(H::zero_bytes()[i]));
230→        let changelog_entry = ChangelogEntry { path, index: 0 };
231→        self.changelog.push(changelog_entry);
232→
233→        // Initialize filled subtrees.
234→        for i in 0..self.height {
235→            self.filled_subtrees.push(H::zero_bytes()[i]).unwrap();
236→        }
237→
238→        // Initialize canopy.
239→        for level_i in 0..self.canopy_depth {
240→            let level_nodes = 1 << (level_i + 1);
241→            for _ in 0..level_nodes {
242→                let node = H::zero_bytes()[self.height - level_i - 1];
243→                self.canopy.push(node)?;
244→            }
245→        }
246→
247→        Ok(())
248→    }
249→
250→    /// Returns the index of the current changelog entry.
251→    pub fn changelog_index(&self) -> usize {
252→        self.changelog.last_index()
253→    }
254→
255→    /// Returns the index of the current root in the tree's root buffer.
256→    pub fn root_index(&self) -> usize {
257→        self.roots.last_index()
258→    }
259→
260→    /// Returns the current root.
261→    pub fn root(&self) -> [u8; 32] {
262→        // PANICS: This should never happen - there is always a root in the
263→        // tree and `self.root_index()` should always point to an existing index.
264→        self.roots[self.root_index()]
265→    }
266→
267→    pub fn current_index(&self) -> usize {
268→        let next_index = self.next_index();
269→        if next_index > 0 {
270→            next_index - 1
271→        } else {
272→            next_index
273→        }
274→    }
275→
276→    pub fn next_index(&self) -> usize {
277→        unsafe { *self.next_index }
278→    }
279→
280→    pub fn inc_next_index(&mut self) -> Result<(), ConcurrentMerkleTreeError> {
281→        unsafe {
282→            *self.next_index = self
283→                .next_index()
284→                .checked_add(1)
285→                .ok_or(ConcurrentMerkleTreeError::IntegerOverflow)?;
286→        }
287→        Ok(())
288→    }
289→
290→    pub fn sequence_number(&self) -> usize {
291→        unsafe { *self.sequence_number }
292→    }
293→
294→    pub fn inc_sequence_number(&mut self) -> Result<(), ConcurrentMerkleTreeError> {
295→        unsafe {
296→            *self.sequence_number = self
297→                .sequence_number()
298→                .checked_add(1)
299→                .ok_or(ConcurrentMerkleTreeError::IntegerOverflow)?;
300→        }
301→        Ok(())
302→    }
303→
304→    pub fn rightmost_leaf(&self) -> [u8; 32] {
305→        unsafe { *self.rightmost_leaf }
306→    }
307→
308→    fn set_rightmost_leaf(&mut self, leaf: &[u8; 32]) {
309→        unsafe { *self.rightmost_leaf = *leaf };
310→    }
311→
312→    pub fn update_proof_from_canopy(
313→        &self,
314→        leaf_index: usize,
315→        proof: &mut BoundedVec<[u8; 32]>,
316→    ) -> Result<(), ConcurrentMerkleTreeError> {
317→        let mut node_index = ((1 << self.height) + leaf_index) >> (self.height - self.canopy_depth);
318→        while node_index > 1 {
319→            // `node_index - 2` maps to the canopy index.
320→            let canopy_index = node_index - 2;
321→            #[allow(clippy::manual_is_multiple_of)]
322→            let canopy_index = if canopy_index % 2 == 0 {
323→                canopy_index + 1
324→            } else {
325→                canopy_index - 1
326→            };
327→            proof.push(self.canopy[canopy_index])?;
328→            node_index >>= 1;
329→        }
330→
331→        Ok(())
332→    }
333→
334→    /// Returns an iterator with changelog entries newer than the requested
335→    /// `changelog_index`.
336→    pub fn changelog_entries(
337→        &self,
338→        changelog_index: usize,
339→    ) -> Result<Skip<CyclicBoundedVecIterator<'_, ChangelogEntry<HEIGHT>>>, ConcurrentMerkleTreeError>
340→    {
341→        // `CyclicBoundedVec::iter_from` returns an iterator which includes also
342→        // the element indicated by the provided index.
343→        //
344→        // However, we want to iterate only on changelog events **newer** than
345→        // the provided one.
346→        //
347→        // Calling `iter_from(changelog_index + 1)` wouldn't work. If
348→        // `changelog_index` points to the newest changelog entry,
349→        // `changelog_index + 1` would point to the **oldest** changelog entry.
350→        // That would result in iterating over the whole changelog - from the
351→        // oldest to the newest element.
352→        Ok(self.changelog.iter_from(changelog_index)?.skip(1))
353→    }
354→
355→    /// Updates the given Merkle proof.
356→    ///
357→    /// The update is performed by checking whether there are any new changelog
358→    /// entries and whether they contain changes which affect the current
359→    /// proof. To be precise, for each changelog entry, it's done in the
360→    /// following steps:
361→    ///
362→    /// * Check if the changelog entry was directly updating the `leaf_index`
363→    ///   we are trying to update.
364→    ///   * If no (we check that condition first, since it's more likely),
365→    ///     it means that there is a change affecting the proof, but not the
366→    ///     leaf.
367→    ///     Check which element from our proof was affected by the change
368→    ///     (using the `critbit_index` method) and update it (copy the new
369→    ///     element from the changelog to our updated proof).
370→    ///   * If yes, it means that the same leaf we want to update was already
371→    ///     updated. In such case, updating the proof is not possible.
372→    pub fn update_proof_from_changelog(
373→        &self,
374→        changelog_index: usize,
375→        leaf_index: usize,
376→        proof: &mut BoundedVec<[u8; 32]>,
377→    ) -> Result<(), ConcurrentMerkleTreeError> {
378→        // Iterate over changelog entries starting from the requested
379→        // `changelog_index`.
380→        //
381→        // Since we are interested only in subsequent, new changelog entries,
382→        // skip the first result.
383→        for changelog_entry in self.changelog_entries(changelog_index)? {
384→            changelog_entry.update_proof(leaf_index, proof)?;
385→        }
386→
387→        Ok(())
388→    }
389→
390→    /// Checks whether the given Merkle `proof` for the given `node` (with index
391→    /// `i`) is valid. The proof is valid when computing parent node hashes using
392→    /// the whole path of the proof gives the same result as the given `root`.
393→    pub fn validate_proof(
394→        &self,
395→        leaf: &[u8; 32],
396→        leaf_index: usize,
397→        proof: &BoundedVec<[u8; 32]>,
398→    ) -> Result<(), ConcurrentMerkleTreeError> {
399→        let expected_root = self.root();
400→        let computed_root = compute_root::<H>(leaf, leaf_index, proof)?;
401→        if computed_root == expected_root {
402→            Ok(())
403→        } else {
404→            Err(ConcurrentMerkleTreeError::InvalidProof(
405→                expected_root,
406→                computed_root,
407→            ))
408→        }
409→    }
410→
411→    /// Updates the leaf under `leaf_index` with the `new_leaf` value.
412→    ///
413→    /// 1. Computes the new path and root from `new_leaf` and Merkle proof
414→    ///    (`proof`).
415→    /// 2. Stores the new path as the latest changelog entry and increments the
416→    ///    latest changelog index.
417→    /// 3. Stores the latest root and increments the latest root index.
418→    /// 4. If new leaf is at the rightmost index, stores it as the new
419→    ///    rightmost leaft and stores the Merkle proof as the new rightmost
420→    ///    proof.
421→    ///
422→    /// # Validation
423→    ///
424→    /// This method doesn't validate the proof. Caller is responsible for
425→    /// doing that before.
426→    fn update_leaf_in_tree(
427→        &mut self,
428→        new_leaf: &[u8; 32],
429→        leaf_index: usize,
430→        proof: &BoundedVec<[u8; 32]>,
431→    ) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
432→        let mut changelog_entry = ChangelogEntry::default_with_index(leaf_index);
433→        let mut current_node = *new_leaf;
434→        for (level, sibling) in proof.iter().enumerate() {
435→            changelog_entry.path[level] = Some(current_node);
436→            current_node = compute_parent_node::<H>(&current_node, sibling, leaf_index, level)?;
437→        }
438→
439→        self.inc_sequence_number()?;
440→
441→        self.roots.push(current_node);
442→
443→        // Check if the leaf is the last leaf in the tree.
444→        if self.next_index() < (1 << self.height) {
445→            changelog_entry.update_proof(self.next_index(), &mut self.filled_subtrees)?;
446→            // Check if we updated the rightmost leaf.
447→            if leaf_index >= self.current_index() {
448→                self.set_rightmost_leaf(new_leaf);
449→            }
450→        }
451→        self.changelog.push(changelog_entry);
452→
453→        if self.canopy_depth > 0 {
454→            self.update_canopy(self.changelog.last_index(), 1);
455→        }
456→
457→        Ok((self.changelog.last_index(), self.sequence_number()))
458→    }
459→
460→    /// Replaces the `old_leaf` under the `leaf_index` with a `new_leaf`, using
461→    /// the given `proof` and `changelog_index` (pointing to the changelog entry
462→    /// which was the newest at the time of preparing the proof).
463→    #[inline(never)]
464→    pub fn update(
465→        &mut self,
466→        changelog_index: usize,
467→        old_leaf: &[u8; 32],
468→        new_leaf: &[u8; 32],
469→        leaf_index: usize,
470→        proof: &mut BoundedVec<[u8; 32]>,
471→    ) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
472→        let expected_proof_len = self.height - self.canopy_depth;
473→        if proof.len() != expected_proof_len {
474→            return Err(ConcurrentMerkleTreeError::InvalidProofLength(
475→                expected_proof_len,
476→                proof.len(),
477→            ));
478→        }
479→        if leaf_index >= self.next_index() {
480→            return Err(ConcurrentMerkleTreeError::CannotUpdateEmpty);
481→        }
482→
483→        if self.canopy_depth > 0 {
484→            self.update_proof_from_canopy(leaf_index, proof)?;
485→        }
486→        if changelog_index != self.changelog_index() {
487→            self.update_proof_from_changelog(changelog_index, leaf_index, proof)?;
488→        }
489→        self.validate_proof(old_leaf, leaf_index, proof)?;
490→        self.update_leaf_in_tree(new_leaf, leaf_index, proof)
491→    }
492→
493→    /// Appends a new leaf to the tree.
494→    pub fn append(&mut self, leaf: &[u8; 32]) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
495→        self.append_batch(&[leaf])
496→    }
497→
498→    /// Appends a new leaf to the tree. Saves Merkle proof to the provided
499→    /// `proof` reference.
500→    pub fn append_with_proof(
501→        &mut self,
502→        leaf: &[u8; 32],
503→        proof: &mut BoundedVec<[u8; 32]>,
504→    ) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
505→        self.append_batch_with_proofs(&[leaf], &mut [proof])
506→    }
507→
508→    /// Appends a batch of new leaves to the tree.
509→    pub fn append_batch(
510→        &mut self,
511→        leaves: &[&[u8; 32]],
512→    ) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
513→        self.append_batch_common::<false>(leaves, None)
514→    }
515→
516→    /// Appends a batch of new leaves to the tree. Saves Merkle proofs to the
517→    /// provided `proofs` slice.
518→    pub fn append_batch_with_proofs(
519→        &mut self,
520→        leaves: &[&[u8; 32]],
521→        proofs: &mut [&mut BoundedVec<[u8; 32]>],
522→    ) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
523→        self.append_batch_common::<true>(leaves, Some(proofs))
524→    }
525→
526→    /// Appends a batch of new leaves to the tree.
527→    ///
528→    /// This method contains the common logic and is not intended for external
529→    /// use. Callers should choose between [`append_batch`](ConcurrentMerkleTree::append_batch)
530→    /// and [`append_batch_with_proofs`](ConcurrentMerkleTree::append_batch_with_proofs).
531→    fn append_batch_common<
532→        // The only purpose of this const generic is to force compiler to
533→        // produce separate functions, with and without proof.
534→        //
535→        // Unfortunately, using `Option` is not enough:
536→        //
537→        // https://godbolt.org/z/fEMMfMdPc
538→        // https://godbolt.org/z/T3dxnjMzz
539→        //
540→        // Using the const generic helps and ends up generating two separate
541→        // functions:
542→        //
543→        // https://godbolt.org/z/zGnM7Ycn1
544→        const WITH_PROOFS: bool,
545→    >(
546→        &mut self,
547→        leaves: &[&[u8; 32]],
548→        // Slice for saving Merkle proofs.
549→        //
550→        // Currently it's used only for indexed Merkle trees.
551→        mut proofs: Option<&mut [&mut BoundedVec<[u8; 32]>]>,
552→    ) -> Result<(usize, usize), ConcurrentMerkleTreeError> {
553→        if leaves.is_empty() {
554→            return Err(ConcurrentMerkleTreeError::EmptyLeaves);
555→        }
556→        if (self.next_index() + leaves.len() - 1) >= 1 << self.height {
557→            return Err(ConcurrentMerkleTreeError::TreeIsFull);
558→        }
559→        if leaves.len() > self.changelog.capacity() {
560→            return Err(ConcurrentMerkleTreeError::BatchGreaterThanChangelog(
561→                leaves.len(),
562→                self.changelog.capacity(),
563→            ));
564→        }
565→
566→        let first_changelog_index = (self.changelog.last_index() + 1) % self.changelog.capacity();
567→        let first_sequence_number = self.sequence_number() + 1;
568→
569→        for (leaf_i, leaf) in leaves.iter().enumerate() {
570→            let mut current_index = self.next_index();
571→
572→            self.changelog
573→                .push(ChangelogEntry::<HEIGHT>::default_with_index(current_index));
574→            let changelog_index = self.changelog_index();
575→
576→            let mut current_node = **leaf;
577→
578→            self.changelog[changelog_index].path[0] = Some(**leaf);
579→
580→            for i in 0..self.height {
581→                #[allow(clippy::manual_is_multiple_of)]
582→                let is_left = current_index % 2 == 0;
583→
584→                if is_left {
585→                    // If the current node is on the left side:
586→                    //
587→                    //     U
588→                    //    / \
589→                    //  CUR  SIB
590→                    //  /     \
591→                    // N       N
592→                    //
593→                    // * The sibling (on the right) is a "zero node".
594→                    // * That "zero node" becomes a part of Merkle proof.
595→                    // * The upper (next current) node is `H(cur, Ø)`.
596→                    let empty_node = H::zero_bytes()[i];
597→
598→                    if WITH_PROOFS {
599→                        // PANICS: `proofs` should be always `Some` at this point.
600→                        proofs.as_mut().unwrap()[leaf_i].push(empty_node)?;
601→                    }
602→
603→                    self.filled_subtrees[i] = current_node;
604→
605→                    // For all non-terminal leaves, stop computing parents as
606→                    // soon as we are on the left side.
607→                    // Computation of the parent nodes is going to happen in
608→                    // the next iterations.
609→                    if leaf_i < leaves.len() - 1 {
610→                        break;
611→                    }
612→
613→                    current_node = H::hashv(&[&current_node, &empty_node])?;
614→                } else {
615→                    // If the current node is on the right side:
616→                    //
617→                    //     U
618→                    //    / \
619→                    //  SIB  CUR
620→                    //  /     \
621→                    // N       N
622→                    // * The sigling on the left is a "filled subtree".
623→                    // * That "filled subtree" becomes a part of Merkle proof.
624→                    // * The upper (next current) node is `H(sib, cur)`.
625→
626→                    if WITH_PROOFS {
627→                        // PANICS: `proofs` should be always `Some` at this point.
628→                        proofs.as_mut().unwrap()[leaf_i].push(self.filled_subtrees[i])?;
629→                    }
630→
631→                    current_node = H::hashv(&[&self.filled_subtrees[i], &current_node])?;
632→                }
633→
634→                if i < self.height - 1 {
635→                    self.changelog[changelog_index].path[i + 1] = Some(current_node);
636→                }
637→
638→                current_index /= 2;
639→            }
640→
641→            if leaf_i == leaves.len() - 1 {
642→                self.roots.push(current_node);
643→            } else {
644→                // Photon returns only the sequence number and we use it in the
645→                // JS client and forester to derive the root index. Therefore,
646→                // we need to emit a "zero root" to not break that property.
647→                self.roots.push([0u8; 32]);
648→            }
649→
650→            self.inc_next_index()?;
651→            self.inc_sequence_number()?;
652→
653→            self.set_rightmost_leaf(leaf);
654→        }
655→
656→        if self.canopy_depth > 0 {
657→            self.update_canopy(first_changelog_index, leaves.len());
658→        }
659→
660→        Ok((first_changelog_index, first_sequence_number))
661→    }
662→
663→    fn update_canopy(&mut self, first_changelog_index: usize, num_leaves: usize) {
664→        for i in 0..num_leaves {
665→            let changelog_index = (first_changelog_index + i) % self.changelog.capacity();
666→            for (i, path_node) in self.changelog[changelog_index]
667→                .path
668→                .iter()
669→                .rev()
670→                .take(self.canopy_depth)
671→                .enumerate()
672→            {
673→                if let Some(path_node) = path_node {
674→                    let level = self.height - i - 1;
675→                    let index = (1 << (self.height - level))
676→                        + (self.changelog[changelog_index].index >> level);
677→                    // `index - 2` maps to the canopy index.
678→                    self.canopy[(index - 2) as usize] = *path_node;
679→                }
680→            }
681→        }
682→    }
683→}
684→
685→impl<H, const HEIGHT: usize> Drop for ConcurrentMerkleTree<H, HEIGHT>
686→where
687→    H: Hasher,
688→{
689→    fn drop(&mut self) {
690→        let layout = Layout::new::<usize>();
691→        unsafe { alloc::dealloc(self.next_index as *mut u8, layout) };
692→
693→        let layout = Layout::new::<usize>();
694→        unsafe { alloc::dealloc(self.sequence_number as *mut u8, layout) };
695→
696→        let layout = Layout::new::<[u8; 32]>();
697→        unsafe { alloc::dealloc(self.rightmost_leaf as *mut u8, layout) };
698→    }
699→}
700→
701→impl<H, const HEIGHT: usize> PartialEq for ConcurrentMerkleTree<H, HEIGHT>
702→where
703→    H: Hasher,
704→{
705→    fn eq(&self, other: &Self) -> bool {
706→        self.height.eq(&other.height)
707→            && self.canopy_depth.eq(&other.canopy_depth)
708→            && self.next_index().eq(&other.next_index())
709→            && self.sequence_number().eq(&other.sequence_number())
710→            && self.rightmost_leaf().eq(&other.rightmost_leaf())
711→            && self
712→                .filled_subtrees
713→                .as_slice()
714→                .eq(other.filled_subtrees.as_slice())
715→            && self.changelog.iter().eq(other.changelog.iter())
716→            && self.roots.iter().eq(other.roots.iter())
717→            && self.canopy.as_slice().eq(other.canopy.as_slice())
718→    }
719→}
