 67→impl_to_byte_array_for_integer_type!(u16);
 68→impl_to_byte_array_for_integer_type!(i32);
 69→impl_to_byte_array_for_integer_type!(u32);
 70→impl_to_byte_array_for_integer_type!(i64);
