 73→impl_to_byte_array_for_integer_type!(u128);
 74→
 75→// Macro for implementing ToByteArray for zero-copy types
 76→#[cfg(feature = "zero-copy")]
 77→macro_rules! impl_to_byte_array_for_zero_copy_type {
 78→    ($zero_copy_type:ty, $primitive_type:ty) => {
 79→        impl ToByteArray for $zero_copy_type {
 80→            const IS_PRIMITIVE: bool = true;
 81→            const NUM_FIELDS: usize = 1;
 82→
 83→            fn to_byte_array(&self) -> Result<[u8; 32], HasherError> {
 84→                let value: $primitive_type = (*self).into();
 85→                value.to_byte_array()
 86→            }
 87→        }
 88→    };
 89→}
 90→
 91→// ToByteArray implementations for zero-copy types
 92→#[cfg(feature = "zero-copy")]
 93→impl_to_byte_array_for_zero_copy_type!(zerocopy::little_endian::U16, u16);
 94→#[cfg(feature = "zero-copy")]
 95→impl_to_byte_array_for_zero_copy_type!(zerocopy::little_endian::U32, u32);
 96→#[cfg(feature = "zero-copy")]
 97→impl_to_byte_array_for_zero_copy_type!(zerocopy::little_endian::U64, u64);
 98→#[cfg(feature = "zero-copy")]
 99→impl_to_byte_array_for_zero_copy_type!(zerocopy::little_endian::I16, i16);
100→#[cfg(feature = "zero-copy")]
101→impl_to_byte_array_for_zero_copy_type!(zerocopy::little_endian::I32, i32);
102→#[cfg(feature = "zero-copy")]
103→impl_to_byte_array_for_zero_copy_type!(zerocopy::little_endian::I64, i64);
104→
105→/// Example usage:
106→/// impl_to_byte_array_for_array! {
107→///     MyCustomType,
108→///     1 => [0],
109→///     2 => [0, 1]
110→/// }
111→#[macro_export]
112→macro_rules! impl_to_byte_array_for_array {
113→    // First specify the type T, then for each array, specify the length and indices
114→    ($t:ty, $( $len:literal => [$($index:tt),*] );* $(;)?) => {
115→        $(
116→            impl ToByteArray for [$t; $len] {
117→                const NUM_FIELDS: usize = $len;
118→                const IS_PRIMITIVE: bool = false;
119→
120→                fn to_byte_array(&self) -> Result<[u8; 32], HasherError> {
121→                    let arrays = [$(self[$index].to_byte_array()?),*];
122→                    let slices = [$(arrays[$index].as_slice()),*];
123→                    Poseidon::hashv(&slices)
124→                }
125→            }
126→        )*
127→    }
128→}
129→
130→// Implementation for [u8; N] arrays with N <= 31
131→macro_rules! impl_to_byte_array_for_u8_array {
132→    ($size:expr) => {
133→        impl ToByteArray for [u8; $size] {
134→            const NUM_FIELDS: usize = 1;
135→
136→            fn to_byte_array(&self) -> Result<[u8; 32], HasherError> {
137→                let mut result = [0u8; 32];
138→                result[32 - $size..].copy_from_slice(self.as_slice());
139→                Ok(result)
140→            }
141→        }
142→    };
143→}
144→
145→// Implement for common array sizes until 31 so that it is less than field size.
146→impl_to_byte_array_for_u8_array!(1);
147→impl_to_byte_array_for_u8_array!(2);
148→impl_to_byte_array_for_u8_array!(4);
149→impl_to_byte_array_for_u8_array!(5);
150→impl_to_byte_array_for_u8_array!(6);

  1→//! # Light Account
  2→//!
  3→//! LightAccount wraps the compressed account data so that it is easy to use similar to anchor Account.
  4→//! LightAccount sets the discriminator and creates the compressed account data hash.
  5→//!
  6→//! Data structs used with LightAccount must implement the traits:
  7→//! - LightDiscriminator
  8→//! - BorshSerialize, BorshDeserialize
  9→//! - Debug, Default, Clone
 10→//!
 11→//! ### Account Data Hashing
 12→//!
 13→//! Sha256 data hashing is recommended for most use cases.
 14→//! Account data is serialized into a vector with borsh and hashed with Sha256.
 15→//!
 16→//! Poseidon data hashing is recommended for zk use cases.
 17→//! The data struct needs to implement the DataHasher trait.
 18→//! The LightHasher macro derives, the DataHasher trait. The hashing scheme resembles the struct layout.
 19→//! Alternatively, DataHasher can be implemented manually.
 20→//! Poseidon hashing is CU intensive and has limitations with regards to hash inputs see Poseidon module for details.
 21→//!
 22→//!
 23→//! ### Compressed account with LightDiscriminator
 24→//! ```
 25→//! use light_sdk::LightDiscriminator;
 26→//! use solana_pubkey::Pubkey;
 27→//! use borsh::{BorshSerialize, BorshDeserialize};
 28→//! #[derive(Clone, Debug, Default, LightDiscriminator, BorshSerialize, BorshDeserialize)]
 29→//! pub struct CounterAccount {
 30→//!     pub owner: Pubkey,
 31→//!     pub counter: u64,
 32→//! }
 33→//! ```
 34→//!
 35→//!
 36→//! ### Create compressed account
 37→//! ```rust
 38→//! # use light_sdk::{LightAccount, LightDiscriminator};
 39→//! # use borsh::{BorshSerialize, BorshDeserialize};
 40→//! # use solana_pubkey::Pubkey;
 41→//! #
 42→//! # #[derive(Clone, Debug, Default, LightDiscriminator, BorshSerialize, BorshDeserialize)]
 43→//! # pub struct CounterAccount {
 44→//! #     pub owner: Pubkey,
 45→//! #     pub counter: u64,
 46→//! # }
 47→//! #
 48→//! # let program_id = Pubkey::new_unique();
 49→//! # let address = [0u8; 32];
 50→//! # let output_tree_index = 0u8;
 51→//! # let owner = Pubkey::new_unique();
 52→//! let mut my_compressed_account = LightAccount::<CounterAccount>::new_init(
 53→//!     &program_id,
 54→//!     Some(address),
 55→//!     output_tree_index,
 56→//! );
 57→//! // Set data:
 58→//! my_compressed_account.owner = owner;
 59→//! ```
 60→//! ### Update compressed account
 61→//! ```rust
 62→//! # use light_sdk::{LightAccount, LightDiscriminator};
 63→//! # use light_sdk::instruction::account_meta::CompressedAccountMeta;
 64→//! # use borsh::{BorshSerialize, BorshDeserialize};
 65→//! # use solana_pubkey::Pubkey;
 66→//! # use solana_program_error::ProgramError;
 67→//! #
 68→//! # #[derive(Clone, Debug, Default, LightDiscriminator, BorshSerialize, BorshDeserialize)]
 69→//! # pub struct CounterAccount {
 70→//! #     pub owner: Pubkey,
 71→//! #     pub counter: u64,
 72→//! # }
 73→//! #
 74→//! # fn example() -> Result<(), ProgramError> {
 75→//! # let program_id = Pubkey::new_unique();
 76→//! # let account_meta = CompressedAccountMeta {
 77→//! #     output_state_tree_index: 0,
 78→//! #     ..Default::default()
 79→//! # };
 80→//! # let compressed_account_data = CounterAccount::default();
 81→//! let mut my_compressed_account = LightAccount::<CounterAccount>::new_mut(
 82→//!     &program_id,
 83→//!     &account_meta,
 84→//!     compressed_account_data,
 85→//! )?;
 86→//! // Increment counter.
 87→//! my_compressed_account.counter += 1;
 88→//! # Ok(())
 89→//! # }
 90→//! ```
 91→//! ### Close compressed account
