 13→/// Computes range node hash based on tree type
 14→pub fn compute_hash_by_tree_type(
 15→    range_node: &indexed_trees::Model,
 16→    tree_type: TreeType,
 17→) -> Result<Hash, IngesterError> {
 18→    match tree_type {
 19→        // AddressV1 uses 3-field hash: H(value, next_index, next_value)
 20→        TreeType::AddressV1 => compute_range_node_hash_v1(range_node).map_err(|e| {
 21→            IngesterError::ParserError(format!("Failed to compute address v1 hash: {}", e))
 22→        }),
 23→        // AddressV2 uses 2-field hash: H(value, next_value)
 24→        // next_index is stored but NOT included in hash (removed in commit e208fa1eb)
 25→        TreeType::AddressV2 => compute_range_node_hash_v2(range_node).map_err(|e| {
 26→            IngesterError::ParserError(format!("Failed to compute address v2 hash: {}", e))
 27→        }),
 28→        _ => Err(IngesterError::ParserError(format!(
 29→            "Unsupported tree type for range node hash computation: {:?}",
 30→            tree_type
 31→        ))),
 32→    }
 33→}
