 35→/// Computes range node hash by looking up tree type from tree pubkey
 36→pub async fn compute_hash_by_tree_pubkey<T>(
 37→    conn: &T,
 38→    range_node: &indexed_trees::Model,
 39→    tree_pubkey: &[u8],
 40→) -> Result<Hash, IngesterError>
 41→where
 42→    T: ConnectionTrait + TransactionTrait,
 43→{
 44→    let pubkey = Pubkey::try_from(tree_pubkey)
 45→        .map_err(|e| IngesterError::ParserError(format!("Invalid pubkey bytes: {}", e)))?;
 46→    let tree_type = TreeInfo::get_tree_type(conn, &pubkey)
 47→        .await
 48→        .map_err(|e| IngesterError::ParserError(format!("Failed to get tree type: {}", e)))?;
 49→    compute_hash_by_tree_type(range_node, tree_type)
 50→}
