 56→        Pubkey,
 57→        crate::ingester::parser::tree_info::TreeInfo,
 58→    >,
 59→) -> Result<Hash, IngesterError> {
 60→    let pubkey = Pubkey::try_from(tree_pubkey)
 61→        .map_err(|e| IngesterError::ParserError(format!("Invalid pubkey bytes: {}", e)))?;
 62→
