 71→/// Computes range node hash for AddressV1 indexed merkle trees.
 72→/// Uses 3-field Poseidon hash: H(value, next_index, next_value)
 73→pub fn compute_range_node_hash_v1(node: &indexed_trees::Model) -> Result<Hash, IngesterError> {
 74→    let mut poseidon = Poseidon::<Fr>::new_circom(3).unwrap();
 75→    let mut next_index_bytes = vec![0u8; 32];
 76→    let index_be = node.next_index.to_be_bytes();
 77→    next_index_bytes[24..32].copy_from_slice(&index_be);
 78→
 79→    Hash::try_from(
 80→        poseidon
 81→            .hash_bytes_be(&[&node.value, &next_index_bytes, &node.next_value])
 82→            .map_err(|e| IngesterError::ParserError(format!("Failed to compute hash v1: {}", e)))
 83→            .map(|x| x.to_vec())?,
 84→    )
 85→    .map_err(|e| IngesterError::ParserError(format!("Failed to convert hash v1: {}", e)))
 86→}
 87→
 88→/// Computes range node hash for AddressV2 indexed merkle trees.
 89→/// Uses 2-field Poseidon hash: H(value, next_value)
 90→/// Note: next_index is stored in the database but NOT included in the hash.
 91→/// This change was introduced in commit e208fa1eb ("remove next_index from circuit").
 92→pub fn compute_range_node_hash_v2(node: &indexed_trees::Model) -> Result<Hash, IngesterError> {
 93→    let mut poseidon = Poseidon::<Fr>::new_circom(2).unwrap();
 94→
 95→    Hash::try_from(
 96→        poseidon
 97→            .hash_bytes_be(&[&node.value, &node.next_value])
 98→            .map_err(|e| IngesterError::ParserError(format!("Failed to compute hash v2: {}", e)))
 99→            .map(|x| x.to_vec())?,
100→    )
101→    .map_err(|e| IngesterError::ParserError(format!("Failed to convert hash v2: {}", e)))
102→}
